// Time:  O(n)
// Space: O(n)

// hash table
class Solution {
public:
    int minimumOperations(vector<int>& nums) {
        unordered_set<int> lookup;
        for (const auto& x : nums) {
            if (x) {
                lookup.emplace(x);
            }
        }
        return size(lookup);
    }
};

# Time:  O(n)
# Space: O(n)

# hash table
class Solution(object):
    def minimumOperations(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        return len({x for x in nums if x})
